-- =============================================================================
-- create_gold_views.sql  —  safe to re-run
-- Before running: set "Use database" dropdown in Synapse Studio to gold_db
-- GO separates each statement into its own batch (required for CREATE VIEW)
-- =============================================================================

CREATE OR ALTER VIEW Sales_CountryRegionCurrency AS
SELECT * FROM OPENROWSET(
    BULK 'https://sadataeng260524dev.dfs.core.windows.net/gold/Sales/CountryRegionCurrency/',
    FORMAT = 'DELTA'
) AS [result];
GO

